#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b) {
    int x = *(const int *)a, y = *(const int *)b;
    return (x > y) - (x < y);
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int ans = 0;
        if (N <= 2) {
            ans = 1;
            for (int i = 1; i < N; ++i) if (a[i-1] > a[i]) { ans = 0; break; }
        } else if (N == 3) {
            int b[3]; for (int i = 0; i < 3; ++i) b[i] = a[i];
            qsort(b, 3, sizeof(int), cmp);
            ans = (a[1] == b[1]);
        } else {
            ans = 1; // N >= 4
        }
        printf(ans ? "YES\n" : "NO\n");
        free(a);
    }
    return 0;
}

